using System;
using System.DirectoryServices;

public static bool AuthenticateUser(string username, string password)
{
    // Construct an LDAP query to find the user
    DirectoryEntry root = new DirectoryEntry("LDAP://mydomain.com");
    DirectorySearcher searcher = new DirectorySearcher(root);
    searcher.Filter = $"(&(objectClass=user)(sAMAccountName={username}))";

    // Authenticate the user
    try
    {
        SearchResult result = searcher.FindOne();
        if (result == null)
        {
            return false;
        }

        DirectoryEntry user = result.GetDirectoryEntry();
        user.AuthenticationType = AuthenticationTypes.Secure;
        user.Username = username;
        user.Password = password;

        bool authenticated = user.AuthenticationType == AuthenticationTypes.Secure;

        if (authenticated)
        {
            Console.WriteLine("User successfully authenticated.");
        }
        else
        {
            Console.WriteLine("Invalid credentials provided.");
        }

        return authenticated;
    }
    catch (Exception e)
    {
        Console.WriteLine($"Error occurred while attempting to authenticate user: {e.Message}");
        return false;
    }
}